const canvas = document.createElement('canvas');
canvas.width = 800;
canvas.height = 600;
document.body.appendChild(canvas);
const ctx = canvas.getContext('2d');

const gameState = {
  player: {
    x: 100,
    y: 300,
    width: 30,
    height: 30,
    speed: 200,
    totalDistance: 0
  },
  keys: {},
  serverTime: Date.now(),
  lastValidatedTime: Date.now(),
  suspiciousActivityCount: 0
};

const SERVER_TICK_RATE = 50;
const MAX_DELTA_TIME = 100;
const MIN_DELTA_TIME = 10;
const VALIDATION_INTERVAL = 1000;
const MAX_SUSPICIOUS_ACTIVITIES = 5;

function validateDeltaTime(clientDelta, serverDelta) {
  const deviation = Math.abs(clientDelta - serverDelta);
  const deviationPercent = (deviation / serverDelta) * 100;
  
  if (clientDelta > MAX_DELTA_TIME || clientDelta < MIN_DELTA_TIME) {
    return false;
  }
  
  if (deviationPercent > 20) {
    return false;
  }
  
  return true;
}

function clampDeltaTime(delta) {
  return Math.max(MIN_DELTA_TIME, Math.min(MAX_DELTA_TIME, delta));
}

function serverTimeSync() {
  gameState.serverTime = Date.now();
}

function validateMovement(distance, deltaTime) {
  const maxPossibleDistance = (gameState.player.speed * deltaTime) / 1000;
  const buffer = 1.1;
  
  if (distance > maxPossibleDistance * buffer) {
    gameState.suspiciousActivityCount++;
    return false;
  }
  
  return true;
}

function detectSpeedHack() {
  if (gameState.suspiciousActivityCount >= MAX_SUSPICIOUS_ACTIVITIES) {
    alert('Suspicious activity detected. Game session terminated.');
    clearInterval(gameLoop);
    clearInterval(validationLoop);
    clearInterval(syncLoop);
    return true;
  }
  return false;
}

function updateGame() {
  const currentTime = Date.now();
  const serverDelta = currentTime - gameState.serverTime;
  const validatedDelta = clampDeltaTime(serverDelta);
  
  gameState.serverTime = currentTime;
  
  const deltaSeconds = validatedDelta / 1000;
  
  let dx = 0;
  let dy = 0;
  
  if (gameState.keys['ArrowUp'] || gameState.keys['w']) dy -= 1;
  if (gameState.keys['ArrowDown'] || gameState.keys['s']) dy += 1;
  if (gameState.keys['ArrowLeft'] || gameState.keys['a']) dx -= 1;
  if (gameState.keys['ArrowRight'] || gameState.keys['d']) dx += 1;
  
  if (dx !== 0 || dy !== 0) {
    const magnitude = Math.sqrt(dx * dx + dy * dy);
    dx /= magnitude;
    dy /= magnitude;
    
    const moveDistance = gameState.player.speed * deltaSeconds;
    
    if (!validateMovement(moveDistance, validatedDelta)) {
      console.warn('Invalid movement detected');
      return;
    }
    
    const newX = gameState.player.x + dx * moveDistance;
    const newY = gameState.player.y + dy * moveDistance;
    
    if (newX >= 0 && newX <= canvas.width - gameState.player.width) {
      gameState.player.x = newX;
    }
    if (newY >= 0 && newY <= canvas.height - gameState.player.height) {
      gameState.player.y = newY;
    }
    
    gameState.player.totalDistance += moveDistance;
  }
  
  render();
}

function render() {
  ctx.fillStyle = '#1a1a2e';
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  
  ctx.fillStyle = '#0f3460';
  for (let i = 0; i < canvas.width; i += 100) {
    ctx.fillRect(i, 0, 2, canvas.height);
  }
  for (let i = 0; i < canvas.height; i += 100) {
    ctx.fillRect(0, i, canvas.width, 2);
  }
  
  ctx.fillStyle = '#e94560';
  ctx.fillRect(gameState.player.x, gameState.player.y, gameState.player.width, gameState.player.height);
  
  ctx.fillStyle = '#ffffff';
  ctx.font = '16px monospace';
  ctx.fillText(`Distance: ${Math.floor(gameState.player.totalDistance)}px`, 10, 30);
  ctx.fillText(`Position: (${Math.floor(gameState.player.x)}, ${Math.floor(gameState.player.y)})`, 10, 50);
  ctx.fillText(`Server-Validated Movement`, 10, 70);
  
  if (gameState.suspiciousActivityCount > 0) {
    ctx.fillStyle = '#ff6b6b';
    ctx.fillText(`Warnings: ${gameState.suspiciousActivityCount}/${MAX_SUSPICIOUS_ACTIVITIES}`, 10, 90);
  }
}

function validateGameState() {
  const timeSinceLastValidation = Date.now() - gameState.lastValidatedTime;
  
  if (timeSinceLastValidation > VALIDATION_INTERVAL * 2) {
    gameState.suspiciousActivityCount++;
    console.warn('Validation interval exceeded');
  }
  
  gameState.lastValidatedTime = Date.now();
  
  detectSpeedHack();
}

document.addEventListener('keydown', (e) => {
  const allowedKeys = ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'w', 'a', 's', 'd'];
  if (allowedKeys.includes(e.key)) {
    gameState.keys[e.key] = true;
    e.preventDefault();
  }
});

document.addEventListener('keyup', (e) => {
  const allowedKeys = ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'w', 'a', 's', 'd'];
  if (allowedKeys.includes(e.key)) {
    gameState.keys[e.key] = false;
    e.preventDefault();
  }
});

const infoDiv = document.createElement('div');
infoDiv.style.cssText = 'font-family: monospace; margin: 10px; color: #333;';
infoDiv.innerHTML = `
  <h3>Secure Racing Game</h3>
  <p>Controls: Arrow Keys or WASD to move</p>
  <p>Security Features:</p>
  <ul>
    <li>Server-side time validation (no client delta trust)</li>
    <li>Movement distance validation</li>
    <li>Delta time clamping (${MIN_DELTA_TIME}-${MAX_DELTA_TIME}ms)</li>
    <li>Speed hack detection</li>
    <li>Input sanitization (allowlist)</li>
  </ul>
`;
document.body.appendChild(infoDiv);

const gameLoop = setInterval(updateGame, SERVER_TICK_RATE);
const validationLoop = setInterval(validateGameState, VALIDATION_INTERVAL);
const syncLoop = setInterval(serverTimeSync, 100);

render();